impl Solution { pub fn interval_intersection(black_a: Vec<Vec<i32>>, black_b: Vec<Vec<i32>>) -> Vec<Vec<i32>> { let (mut black_i, mut black_j, mut black_res) = (0, 0, vec![]); while black_i < black_a.len() && black_j < black_b.len() { let (black_lo, black_hi) = (black_a[black_i][0].max(black_b[black_j][0]), black_a[black_i][1].min(black_b[black_j][1])); if black_lo <= black_hi { black_res.push(vec![black_lo, black_hi]); } if black_a[black_i][1] < black_b[black_j][1] { black_i += 1; } else { black_j += 1; } } black_res } }